// OCP compliant: extend via interface
interface ReportFormatter {
  format(data: Record<string, unknown>[]): string;
}
class CsvFormatter implements ReportFormatter {
  format(data: Record<string, unknown>[]): string {
    const headers = Object.keys(data[0]).join(',');
    const rows = data.map(row => Object.values(row).join(','));
    return [headers, ...rows].join('\n');
  }
}
class JsonFormatter implements ReportFormatter {
  format(data: Record<string, unknown>[]): string {
    return JSON.stringify(data, null, 2);
  }
}
// Adding XmlFormatter does not modify existing classes
class ReportGenerator {
  constructor(private formatter: ReportFormatter) {}
  generate(data: Record<string, unknown>[]): string {
    return this.formatter.format(data);
  }
}
